'use client';

import React, { useState, useEffect } from 'react';
import { Calculator, TrendingUp, PoundSterling } from 'lucide-react';

const LeadROICalculator = () => {
  const [inputs, setInputs] = useState({
    numLeads: 50,
    conversionRate: 15,
    avgDealValue: 2500,
    commissionRate: 10,
    repeatBusinessRate: 30,
    clientLifetimeYears: 5,
    referralsPerClient: 0.5
  });

  const [results, setResults] = useState({});
  const [selectedVertical, setSelectedVertical] = useState('custom');

  const verticals = {
    mortgages: {
      name: 'Mortgages',
      conversionRate: 15,
      avgDealValue: 250000,
      commissionRate: 0.35,
      repeatBusinessRate: 40,
      clientLifetimeYears: 7,
      referralsPerClient: 0.5
    },
    carInsurance: {
      name: 'Car Finance',
      conversionRate: 22,
      avgDealValue: 25000,
      commissionRate: 2,
      repeatBusinessRate: 25,
      clientLifetimeYears: 4,
      referralsPerClient: 0.4
    },
    businessLoans: {
      name: 'Business Loans',
      conversionRate: 12,
      avgDealValue: 75000,
      commissionRate: 3,
      repeatBusinessRate: 25,
      clientLifetimeYears: 4,
      referralsPerClient: 0.3
    },
    lifeInsurance: {
      name: 'Life Insurance',
      conversionRate: 20,
      avgDealValue: 2400,
      commissionRate: 50,
      repeatBusinessRate: 15,
      clientLifetimeYears: 15,
      referralsPerClient: 0.4
    },
    securedLoans: {
      name: 'Secured Loans',
      conversionRate: 14,
      avgDealValue: 35000,
      commissionRate: 2.5,
      repeatBusinessRate: 20,
      clientLifetimeYears: 3,
      referralsPerClient: 0.4
    },
    businessGrants: {
      name: 'Business Grants',
      conversionRate: 8,
      avgDealValue: 15000,
      commissionRate: 12,
      repeatBusinessRate: 40,
      clientLifetimeYears: 5,
      referralsPerClient: 0.6
    },
    propertyInvestment: {
      name: 'Property Investment',
      conversionRate: 10,
      avgDealValue: 180000,
      commissionRate: 1.5,
      repeatBusinessRate: 60,
      clientLifetimeYears: 10,
      referralsPerClient: 0.8
    },
    custom: {
      name: 'Custom',
      conversionRate: 15,
      avgDealValue: 2500,
      commissionRate: 10,
      repeatBusinessRate: 30,
      clientLifetimeYears: 5,
      referralsPerClient: 0.5
    }
  };

  useEffect(() => {
    if (selectedVertical !== 'custom') {
      const vertical = verticals[selectedVertical];
      setInputs(prev => ({
        ...prev,
        conversionRate: vertical.conversionRate,
        avgDealValue: vertical.avgDealValue,
        commissionRate: vertical.commissionRate,
        repeatBusinessRate: vertical.repeatBusinessRate,
        clientLifetimeYears: vertical.clientLifetimeYears,
        referralsPerClient: vertical.referralsPerClient
      }));
    }
  }, [selectedVertical]);

  useEffect(() => {
    calculateROI();
  }, [inputs]);

  const calculateROI = () => {
    const costPerLead = 100;
    const totalInvestment = inputs.numLeads * costPerLead;
    const leadsConverted = (inputs.numLeads * inputs.conversionRate) / 100;
    
    const initialCommission = (inputs.avgDealValue * inputs.commissionRate) / 100;
    const immediateRevenue = leadsConverted * initialCommission;
    const immediateProfit = immediateRevenue - totalInvestment;
    const immediateROI = totalInvestment > 0 ? (immediateProfit / totalInvestment) * 100 : 0;
    
    const repeatBusinessValue = initialCommission * (inputs.repeatBusinessRate / 100);
    const referralValue = initialCommission * inputs.referralsPerClient;
    const lifetimeValuePerLead = initialCommission + repeatBusinessValue + referralValue;
    
    const totalLifetimeRevenue = leadsConverted * lifetimeValuePerLead;
    const totalLifetimeProfit = totalLifetimeRevenue - totalInvestment;
    const lifetimeROI = totalInvestment > 0 ? (totalLifetimeProfit / totalInvestment) * 100 : 0;
    
    setResults({
      totalInvestment,
      leadsConverted: Math.round(leadsConverted * 10) / 10,
      immediateRevenue,
      immediateProfit,
      immediateROI,
      lifetimeValuePerLead,
      totalLifetimeRevenue,
      totalLifetimeProfit,
      lifetimeROI
    });
  };

  const handleInputChange = (field: string, value: string) => {
    setInputs(prev => ({
      ...prev,
      [field]: parseFloat(value) || 0
    }));
  };

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('en-GB', {
      style: 'currency',
      currency: 'GBP',
      maximumFractionDigits: 0
    }).format(amount);
  };

  const formatPercentage = (percentage: number) => {
    return `${percentage.toFixed(1)}%`;
  };

  return (
    <div className="w-full max-w-4xl mx-auto bg-white border border-gray-200 rounded-lg shadow-sm">
      <div className="p-6 border-b border-gray-200">
        <div className="flex items-center gap-3">
          <Calculator className="w-6 h-6 text-blue-600" />
          <h2 className="text-2xl font-semibold text-gray-900">Lead ROI Calculator</h2>
        </div>
        <p className="text-gray-600 mt-2">Calculate your return on investment for qualified leads</p>
      </div>

      <div className="grid lg:grid-cols-2 divide-y lg:divide-y-0 lg:divide-x divide-gray-200">
        {/* Inputs */}
        <div className="p-6">
          <h3 className="text-lg font-medium text-gray-900 mb-4">Your Business Details</h3>
          
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Industry
              </label>
              <select
                value={selectedVertical}
                onChange={(e) => setSelectedVertical(e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 bg-white"
              >
                {Object.entries(verticals).map(([key, vertical]) => (
                  <option key={key} value={key}>{vertical.name}</option>
                ))}
              </select>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Number of Leads
                </label>
                <input
                  type="number"
                  value={inputs.numLeads}
                  onChange={(e) => handleInputChange('numLeads', e.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  min="1"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Conversion Rate (%)
                </label>
                <input
                  type="number"
                  value={inputs.conversionRate}
                  onChange={(e) => handleInputChange('conversionRate', e.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  min="0"
                  max="100"
                  step="0.1"
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Average Deal Value (£)
                </label>
                <input
                  type="number"
                  value={inputs.avgDealValue}
                  onChange={(e) => handleInputChange('avgDealValue', e.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  min="1"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Commission Rate (%)
                </label>
                <input
                  type="number"
                  value={inputs.commissionRate}
                  onChange={(e) => handleInputChange('commissionRate', e.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  min="0"
                  step="0.01"
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Repeat Business (%)
                </label>
                <input
                  type="number"
                  value={inputs.repeatBusinessRate}
                  onChange={(e) => handleInputChange('repeatBusinessRate', e.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  min="0"
                  max="100"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Referrals Per Client
                </label>
                <input
                  type="number"
                  value={inputs.referralsPerClient}
                  onChange={(e) => handleInputChange('referralsPerClient', e.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  min="0"
                  step="0.1"
                />
              </div>
            </div>
          </div>
        </div>

        {/* Results */}
        <div className="p-6">
          <h3 className="text-lg font-medium text-gray-900 mb-4">Your ROI Breakdown</h3>
          
          <div className="space-y-4">
            <div className="bg-gray-50 p-4 rounded-md">
              <div className="flex justify-between items-center mb-2">
                <span className="text-sm font-medium text-gray-600">Total Investment</span>
                <span className="text-lg font-semibold text-gray-900">
                  {formatCurrency(results.totalInvestment || 0)}
                </span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-sm text-gray-500">Leads Converted</span>
                <span className="text-sm text-gray-700">{results.leadsConverted || 0}</span>
              </div>
            </div>

            <div className="bg-green-50 p-4 rounded-md border border-green-200">
              <div className="flex items-center gap-2 mb-3">
                <TrendingUp className="w-4 h-4 text-green-600" />
                <span className="text-sm font-medium text-green-800">Immediate ROI (90 Days)</span>
              </div>
              <div className="space-y-2">
                <div className="flex justify-between">
                  <span className="text-sm text-green-700">Revenue</span>
                  <span className="text-sm font-medium text-green-800">
                    {formatCurrency(results.immediateRevenue || 0)}
                  </span>
                </div>
                <div className="flex justify-between">
                  <span className="text-sm text-green-700">Profit</span>
                  <span className="text-sm font-medium text-green-800">
                    {formatCurrency(results.immediateProfit || 0)}
                  </span>
                </div>
                <div className="flex justify-between border-t border-green-200 pt-2">
                  <span className="text-sm font-medium text-green-800">ROI</span>
                  <span className={`text-lg font-bold ${(results.immediateROI || 0) > 0 ? 'text-green-800' : 'text-red-600'}`}>
                    {formatPercentage(results.immediateROI || 0)}
                  </span>
                </div>
              </div>
            </div>

            <div className="bg-blue-50 p-4 rounded-md border border-blue-200">
              <div className="flex items-center gap-2 mb-3">
                <PoundSterling className="w-4 h-4 text-blue-600" />
                <span className="text-sm font-medium text-blue-800">Lifetime Value</span>
              </div>
              <div className="space-y-2">
                <div className="flex justify-between">
                  <span className="text-sm text-blue-700">Total Revenue</span>
                  <span className="text-sm font-medium text-blue-800">
                    {formatCurrency(results.totalLifetimeRevenue || 0)}
                  </span>
                </div>
                <div className="flex justify-between">
                  <span className="text-sm text-blue-700">Total Profit</span>
                  <span className="text-sm font-medium text-blue-800">
                    {formatCurrency(results.totalLifetimeProfit || 0)}
                  </span>
                </div>
                <div className="flex justify-between border-t border-blue-200 pt-2">
                  <span className="text-sm font-medium text-blue-800">Lifetime ROI</span>
                  <span className={`text-lg font-bold ${(results.lifetimeROI || 0) > 0 ? 'text-blue-800' : 'text-red-600'}`}>
                    {formatPercentage(results.lifetimeROI || 0)}
                  </span>
                </div>
              </div>
            </div>

            <button className="w-full bg-blue-600 hover:bg-blue-700 text-white font-medium py-2 px-4 rounded-md transition-colors">
              Get Started Today
            </button>
          </div>
        </div>
      </div>

      <div className="px-6 py-4 bg-gray-50 border-t border-gray-200 rounded-b-lg">
        <p className="text-xs text-gray-500 text-center">
          Results are estimates based on industry benchmarks. All leads are £100 each, exclusive, and phone/email verified.
        </p>
      </div>
    </div>
  );
};

export default LeadROICalculator;
